always @ (posedge clk)
begin
	RegWriteW <= RegWriteM;
	MemtoRegW <= MemtoRegM;
	WriteRegW <= WriteRegM;
	ReadDataW <= RD_RAM;
	ALUOutW <= ALUOutM;
end

assign ResultW = (ReadDataW & {32{MemtoRegW}})+(ALUOutW & {32{!MemtoRegW}});

