/*
This block is responsible for getting the selection of the mux either sel1 or sel2
and also the same signal is used to enable the Butterfly Block
*/




module MUX1_Control_unit #(parameter   NFFT = 64, STAGE_NO = 1 )
 (
    input   wire    clk, rst,
    input   wire    start_conv,
    output  reg     sel1  //sel1: used for mux selections
);                


localparam  IDLE    = 0,
            INACTIVE = 1,
            ACTIVE = 2;


//////////////////////////////Internal Counters and Registers/////////////////////////
reg [$clog2(NFFT)-STAGE_NO:0] counter, counter_seq;     //counter used to determine the number of loops to operate the controller
reg [STAGE_NO:0]  end_control_counter;                  //end counter to terminate the controller action
reg [STAGE_NO:0]  end_control_counter_seq; 
reg end_control;                                        //used to indicate the end of the unit usage
reg [1:0] current_state, next_state;                    


//=================== FSM of 3 states==============//


always@(posedge clk or negedge rst) begin
    if(!rst) begin
        current_state <= 'b0;
        counter_seq <= 'b0;
        end_control_counter_seq <='b0;
    end
    else begin
        current_state <= next_state;
        counter_seq <= counter;
        end_control_counter_seq <= end_control_counter;
    end
end


/////////////////////// Next State and Output Logic///////////////////////////////////
always @(*) begin
    sel1         = 1'b0;
    end_control = 1'b1;
    counter     = 'b0;
    end_control_counter = 'b0;
    next_state  = IDLE;

    case (current_state)
        IDLE: begin
            sel1         = 1'b0;
            end_control = 1'b1;
            counter     = 'b0;
            end_control_counter = 'b0;

            if(start_conv) begin
                next_state = INACTIVE;
                end_control_counter = end_control_counter_seq + 1'b1;
                counter     = 'b0;
            end
            else begin
                next_state = IDLE;
                end_control_counter = end_control_counter_seq;
            end
        end


/*Depending on the stage number,this decides how many times we toggle between
inactive and active states.
Inactive means the butterfly is off and passing inputs in the buffer 
to the output of the stage.
Active means the butterfly is on and passes through the mux the result
of the butterfly operation*/

        INACTIVE: begin
            sel1         = 1'b0;
            end_control = 1'b0;
            if(counter_seq == 2**($clog2(NFFT)-STAGE_NO)-1) begin
                if(end_control_counter_seq == 2**(STAGE_NO-1)+1) begin
                    next_state = IDLE;
                    counter = 'b0;
                    end_control_counter = 'b0;
                end
                else begin
                    next_state  = ACTIVE;
                    sel1         = 1'b1;
                    counter = 'b0;
                    end_control_counter = end_control_counter_seq;
                end
            end
            else begin
                counter     = counter_seq + 1'b1;
                next_state  = INACTIVE;
                end_control_counter = end_control_counter_seq;
            end
        end

        ACTIVE: begin
            sel1         = 1'b1;
            end_control = 1'b0;

            if(counter_seq == 2**($clog2(NFFT)-STAGE_NO)-1) begin
                counter = 'b0;
                next_state = INACTIVE;
                sel1         = 1'b0;
                end_control_counter = end_control_counter_seq + 1'b1;
            end
            else begin
                counter     = counter_seq + 1'b1;
                next_state = ACTIVE;
                end_control_counter = end_control_counter_seq;
            end

        end

        default: begin
            sel1         = 1'b0;
            end_control = 1'b1;
            counter     = 'b0;
            end_control_counter = 'b0;
            next_state  = IDLE;
        end
    endcase
end


endmodule

// this module can delay its output for 1 clock cycle if needed
module Top_controller_fft #( parameter   NFFT = 64 )
(
    input   wire                    clk, rst,
    input   wire                    start_FFT,
    output  reg  [$clog2(NFFT)-1:0] start_stage,
    output  reg                     end_FFT, data_valid
);


    localparam  IDLE = 0,
                STAGE_OPERATION = 1,
                DATA_VALID = 3;



//////////////////////////////Internal Counters and Registers/////////////////////////
reg [$clog2(NFFT)-1:0] counter1, counter1_seq;  //to count the number of cycles needed for each stage
reg [$clog2(NFFT)-1:0] counter_limit, counter_limit_seq; //to put limit for number of cycles needed for each stage
reg [$clog2(NFFT)-1:0] start_stage_seq;
reg [1:0]              current_state, next_state;




always @(posedge clk or negedge rst) begin
    if(!rst) begin
        counter1_seq <= 'b0;
        counter_limit_seq <= 'b0;
        current_state <= 2'b0;
        start_stage_seq <= 'b0;

    end
    else begin
        counter1_seq <= counter1;
        counter_limit_seq <= counter_limit;
        current_state <= next_state;
        start_stage_seq <= start_stage;
    end
end



/////////////////////// Next State and Output Logic///////////////////////////////////
always @(*) begin
    counter1 = 'b0;
    counter_limit = 'b0;
    next_state = IDLE;
    start_stage = 'b0;
    end_FFT = 1'b0;
    data_valid = 1'b0;

    case (current_state)
    //---------------IDLE state---------------//
        IDLE: begin
            if(start_FFT) begin
                next_state = STAGE_OPERATION;
                start_stage = 'b1;
                counter1 = 'b0;
                counter_limit = NFFT>>1;
            end
            else begin
                next_state = IDLE;
                start_stage = 'b0;
                counter1 = 'b0;
                counter_limit = 'b0;
            end
        end 

    //-----------start operation state---------//
        STAGE_OPERATION: begin
            counter_limit = counter_limit_seq;
            start_stage = start_stage_seq;
            if(counter1_seq == counter_limit_seq+2) begin
                if(start_stage[$clog2(NFFT)-1] == 1) begin //indicates finishing the last stage
                    //next_state = IDLE;
                    next_state = DATA_VALID;
                    start_stage = 'b0;
                    counter1 = 'b0;
                    counter_limit = NFFT-1;
                    end_FFT = 1'b1;
                    data_valid = 1'b1;
                end
                else begin //indicates starting intermidia
                    next_state = STAGE_OPERATION;
                    start_stage = start_stage_seq<<1;
                    counter1 = 'b0;
                    counter_limit = counter_limit_seq>>1;
                    end_FFT = 1'b0;
                end
            end
            else begin
                next_state = STAGE_OPERATION;
                counter1 = counter1_seq + 1'b1;
            end
        end


    //-------------data valid enable-----------//
        DATA_VALID: begin
            counter_limit = counter_limit_seq;
            data_valid = 1'b1;
            if(counter1_seq == counter_limit_seq) begin //the output finished streaming the reuslts
                next_state = IDLE;
                counter1 = 'b0;
                data_valid = 1'b0;
            end
            else begin // the output is still processing
                next_state = DATA_VALID;
                counter1 = counter1_seq +1'b1;
            end
        end
    endcase
end

endmodule

