	else if (char == 4'b1010)  //if char is 1010, design character a with led lights
	begin
		led_a = 1'b0;
		led_b = 1'b0;
		led_c = 1'b0;
		led_d = 1'b0;
		led_e = 1'b0;
		led_f = 1'b1;
		led_g = 1'b0;
	end
	else if (char == 4'b1011)  //if char is 1011, design character b with led lights
	begin
		led_a = 1'b1;
		led_b = 1'b1;
		led_c = 1'b0;
		led_d = 1'b0;
		led_e = 1'b0;
		led_f = 1'b0;
		led_g = 1'b0;
	end
	else if (char == 4'b1100)  //if char is 1100, design character c with led lights
	begin
		led_a = 1'b1;
		led_b = 1'b1;
		led_c = 1'b1;
		led_d = 1'b0;
		led_e = 1'b0;
		led_f = 1'b1;
		led_g = 1'b0;
	end
	else if (char == 4'b1101)  //if char is 1101, design character d with led lights
	begin
		led_a = 1'b1;
		led_b = 1'b0;
		led_c = 1'b0;
		led_d = 1'b0;
		led_e = 1'b0;
		led_f = 1'b1;
		led_g = 1'b0;
	end
	else if (char == 4'b1110) //if char is 1110, design character E with led lights
	begin
		led_a = 1'b0;
		led_b = 1'b1;
		led_c = 1'b1;
		led_d = 1'b0;
		led_e = 1'b0;
		led_f = 1'b0;
		led_g = 1'b0;
	end
	else							  //if char is 1111, design character F with led lights
	begin
		led_a = 1'b0;
		led_b = 1'b1;
		led_c = 1'b1;
		led_d = 1'b1;
		led_e = 1'b0;
		led_f = 1'b0;
		led_g = 1'b0;
	end
end

//combine all the led lights tou 7bit LED

assign LED[6] = led_a;
assign LED[5] = led_b;
assign LED[4] = led_c;
assign LED[3] = led_d;
assign LED[2] = led_e;
assign LED[1] = led_f;
assign LED[0] = led_g;

endmodule

module ALU_Decoder (
    input   wire    [1:0]      aluOp,
    input   wire    [5:0]      func,
    output  reg     [1:0]      aluController
);

localparam   add = 6'b10_0000,
             sub = 6'b10_0010,
             slt = 6'b10_1010,
             mul = 6'b01_1100;

always @(*)
    begin
        case (aluOp)
            2'b00   :    aluController = 2'b00;
            2'b01   :    aluController = 2'b01;
            2'b10   :    begin
                            case (func)
                                add     :   aluController = 2'b00;
                                sub     :   aluController = 2'b01;
                                slt     :   aluController = 2'b11;
                                mul     :   aluController = 2'b10;
                                default :   aluController = 2'b00;
                            endcase
                         end 
            default :   aluController = 2'b00;
        endcase
    end
endmodule

module ALU #(
    parameter DATA_WIDTH = 32,
    parameter OP_WIDTH   = 2
) (
    output reg   [DATA_WIDTH-1:0]  aluOut, 
    input  wire  [OP_WIDTH-1:0]    aluFunc,
    input  wire  [DATA_WIDTH-1:0]  A, B
);

localparam ADD   =  2'b00;
localparam SUB   =  2'b01;
localparam MUL   =  2'b10;
localparam SLT   =  2'b11;

always @ (*)
    begin 
        case (aluFunc)
            ADD: aluOut = A + B; 
            SUB: aluOut = A - B;
            MUL: aluOut = A * B;
            SLT: aluOut = (A < B) ? {{(DATA_WIDTH - 1){1'b0}}, 1'b1} :  {(DATA_WIDTH){1'b0}};  
            default: aluOut = {(DATA_WIDTH){1'b0}};
        endcase
    end

endmodule

module dataMemory #(
    parameter DATA_WIDTH    = 32,
    parameter ADDRESS_WIDTH = 32,  
    parameter DEPTH         = 128 //NUMBER_OF_ENTRIES
) (
    output wire [DATA_WIDTH-1:0]    readData, 
    output wire [DATA_WIDTH-1:0]    testData,    // For Testing Purposes 
    input  wire [DATA_WIDTH-1:0]    writeData, 
    input  wire [ADDRESS_WIDTH-1:0] addr, 
    input  wire                     writeEnable,
    input  wire                     clk, 
    input  wire                     reset
);
integer i;

reg [DATA_WIDTH-1:0] dMEM [0:DEPTH-1]; 

always @(posedge clk or negedge reset)
    begin 
         if (!reset)
            begin
                for (i = 0; i < DEPTH; i = i + 1)
                    begin
                        dMEM [i] <= {(DATA_WIDTH){1'b0}};
                    end
            end
        else if (writeEnable)
            begin 
                dMEM [addr] <= writeData;
            end
    end

assign readData = dMEM [addr]; //We always read our data asynchronously (regardless of the clock edge)
assign testData = dMEM [{(ADDRESS_WIDTH) {1'b0}}];

endmodule

module Decode_Register (
    input     wire        [31:0]       rd, pcPlus4F,
    input     wire                     clk, en, clear, rst,
    output    reg         [31:0]       instrD, pcPlus4D
);

always @(posedge clk or negedge rst)
        begin
            if(!rst)
                begin
                    instrD   <=    32'b0;
                    pcPlus4D <=    32'b0;
                end
            else if (clear & !en)
                begin
                    instrD   <=    32'b0;
                    pcPlus4D <=    32'b0;
                end
            else if(!en)
                begin
                    instrD   <=    rd;
                    pcPlus4D <=    pcPlus4F;
                end
        end
endmodule

