module Execute_Register (
    output reg              regWriteE, 
    output reg              memToRegE,
    output reg              memWriteE,
    output reg    [1:0]     aluControlE,
    output reg              aluSrcE,
    output reg              regDstE,
    output reg    [31:0]    rd1E,
    output reg    [31:0]    rd2E,
    output reg    [4:0]     rsE, 
    output reg    [4:0]     rtE, 
    output reg    [4:0]     rdE,
    output reg    [31:0]    signImmE, 
    input  wire             regWriteD,
    input  wire             memToRegD,
    input  wire             memWriteD,
    input  wire   [1:0]     aluControlD,
    input  wire             aluSrcD,
    input  wire             regDstD,
    input  wire   [31:0]    rd1D,
    input  wire   [31:0]    rd2D,
    input  wire   [4:0]     rsD, 
    input  wire   [4:0]     rtD, 
    input  wire   [4:0]     rdD,
    input  wire   [31:0]    signImmD, 
    input  wire             clk, 
    input  wire             reset, 
    input  wire             clear
);


always @ (posedge clk or negedge reset)
    begin 
        if (clear | !reset)
            begin
                regWriteE   <=  1'b0;
                memToRegE   <=  1'b0;
                memWriteE   <=  1'b0;
                aluControlE <=  2'b0;
                aluSrcE     <=  1'b0;
                regDstE     <=  1'b0;
                rd1E        <=  32'b0;
                rd2E        <=  32'b0;
                rsE         <=  5'b0;
                rtE         <=  5'b0;
                rdE         <=  5'b0;
                signImmE    <=  32'b0;
            end
        else
            begin
                regWriteE   <=  regWriteD;
                memToRegE   <=  memToRegD;
                memWriteE   <=  memWriteD;
                aluControlE <=  aluControlD;
                aluSrcE     <=  aluSrcD;
                regDstE     <=  regDstD;
                rd1E        <=  rd1D;
                rd2E        <=  rd2D;
                rsE         <=  rsD;
                rtE         <=  rtD;
                rdE         <=  rdD;
                signImmE    <=  signImmD;
            end  
    end

endmodule

module Hazard_Unit (
    input     wire                  regWriteW, regWriteM, memToRegM, regWriteE, memToRegE, jumpD, branchD,
    input     wire      [4:0]       writeRegE, writeRegM, writeRegW, rsE, rsD, rtE, rtD,
    output    wire                  stallD, stallF, flushE,
    output    wire                  forwardAD, forwardBD,
    output    reg       [1:0]       forwardAE, forwardBE
);

wire  lwStall;
wire  branshStall;

assign  lwStall      = (((rsD == rtE) | (rtD == rtE)) & memToRegE);
assign  branshStall  = ((branchD & regWriteE & ((writeRegE == rsD) | (writeRegE == rtD))) | (branchD & memToRegM & ((writeRegM == rsD) | (writeRegM == rtD))));
assign  stallF       = (lwStall | branshStall);
assign  stallD       = (lwStall | branshStall);
assign  flushE       = (lwStall | branshStall | jumpD);
assign  forwardAD    = ((rsD != 0) & (rsD == writeRegM) & regWriteM);
assign  forwardBD    = ((rtD != 0) & (rtD == writeRegM) & regWriteM);

always @(*)
    begin
        if ((rsE != 0) & (rsE == writeRegM) & regWriteM)
                forwardAE = 2'b10;
        else if ((rsE != 0) & (rsE == writeRegW) & regWriteW)
                forwardAE = 2'b01;
        else
                forwardAE = 2'b00;
    end

always @(*)
    begin
        if ((rtE != 0) & (rtE == writeRegM) & regWriteM)
                forwardBE = 2'b10;
        else if ((rtE != 0) & (rtE == writeRegW) & regWriteW)
                forwardBE = 2'b01;
        else
                forwardBE = 2'b00;
    end

endmodule

