module Main_Decoder (
    input    wire     [5:0]     opCode,
    output   reg      [1:0]     aluOp,
    output   reg                memWrite, regWrite, regDest, aluSrc, memtoReg, branch, jump
);

reg     [8:0]     flags;  

localparam loadWord        = 6'b10_0011,
           storeWord       = 6'b10_1011,
           rType           = 6'b00_0000,
           addImmediate    = 6'b00_1000,
           branchIfEqual   = 6'b00_0100,
           jump_inst       = 6'b00_0010; 

always @(*)
    begin
        {jump, aluOp, memWrite, regWrite, regDest, aluSrc, memtoReg, branch} = flags;
    end

always @(*)
    begin
        case (opCode)
            loadWord      : flags = 9'b0_0001_0110;
            storeWord     : flags = 9'b0_0010_0110;
            rType         : flags = 9'b0_1001_1000;
            addImmediate  : flags = 9'b0_0001_0100;
            branchIfEqual : flags = 9'b0_0100_0001;
            jump_inst     : flags = 9'b1_0000_0000;
            default       : flags = 9'b0_0000_0000;
        endcase
    end
endmodule

module Memory_Register (
    input     wire             regWriteE, memToRegE, memWriteE,
    input     wire   [31:0]    aluOutE, writeDataE,
    input     wire   [4:0]     writeRegE,
    input     wire             clk, rst,
    output    reg              regWriteM, memToRegM, memWriteM,
    output    reg    [31:0]    aluOutM, writeDataM,
    output    reg    [4:0]     writeRegM
);

always @(posedge clk or negedge rst)
    begin
        if (!rst)
            begin
                regWriteM    <=    1'b0; 
                memToRegM    <=    1'b0;
                memWriteM    <=    1'b0;
                aluOutM      <=    32'b0; 
                writeDataM   <=    32'b0;
                writeRegM    <=    5'b0;
            end
        else
            begin
                regWriteM    <=   regWriteE; 
                memToRegM    <=   memToRegE;
                memWriteM    <=   memWriteE;
                aluOutM      <=   aluOutE; 
                writeDataM   <=   writeDataE;
                writeRegM    <=   writeRegE;
            end
    end
endmodule

module MUX4X1 #(
    parameter WIDTH = 32
) (
    output reg  [WIDTH-1:0] out, 
    input  wire [WIDTH-1:0] in1, in2, in3,
    input  wire [1:0]       sel
);

always @(*)
    begin
        case (sel)
            2'b00   : out = in1;
            2'b01   : out = in2;
            2'b10   : out = in3;
            default : out = {(WIDTH){1'b0}};
        endcase
    end
endmodule

module MUX #(
    parameter WIDTH = 32
) (
    output wire [WIDTH-1:0] out, 
    input  wire [WIDTH-1:0] in1, in2,
    input  wire             sel
);

assign out = (sel) ? in1 : in2;

